from crewai import Agent
class VerifiedToolAgent(Agent):
    def execute_task(self, task):
        tool_results = super().execute_task(task)
        verified_results = self.validate_tools(tool_results)
        return verified_results

    def validate_tools(self, results):
        for tool_call in results.get('tool_calls', []):
            if not self.verify_tool_execution(tool_call):
                raise ValueError(f"Hallucinated tool: {tool_call}")
        return results

from crewai import Crew
class FactRegistry:
    def __init__(self):
        self.verified_facts = {}

    def register_fact(self, agent_id, fact, source):
        if fact not in self.verified_facts:
            self.verified_facts[fact] = {'source': source, 'agents': [agent_id]}
        else:
            self.verified_facts[fact]['agents'].append(agent_id)

crew = Crew(agents=[...], fact_registry=FactRegistry())

